const { execFile } = require('child_process');
const path = require('path');

function resizeImage(inputFile, outputFile, dimensions, effects) {
    const validEffects = ['grayscale', 'sepia', 'blur', 'enhance'];
    const sanitizedInput = path.basename(inputFile);
    const sanitizedOutput = path.basename(outputFile);
    const sanitizedDimensions = dimensions.match(/^\d+x\d+$/) ? dimensions : null;

    if (!sanitizedDimensions) {
        throw new Error('Invalid dimensions format. Use "WIDTHxHEIGHT".');
    }

    const effectCommands = effects
        .filter(effect => validEffects.includes(effect))
        .map(effect => {
            switch (effect) {
                case 'grayscale':
                    return '-colorspace Gray';
                case 'sepia':
                    return '-sepia-tone 80%';
                case 'blur':
                    return '-blur 0x8';
                case 'enhance':
                    return '-enhance';
                default:
                    return '';
            }
        })
        .join(' ');

    const command = `convert "${sanitizedInput}" ${effectCommands} -resize ${sanitizedDimensions} "${sanitizedOutput}"`;

    execFile('bash', ['-c', command], (error, stdout, stderr) => {
        if (error) {
            console.error(`Error: ${stderr}`);
            return;
        }
        console.log(`Image resized and saved to ${sanitizedOutput}`);
    });
}